object Main { def minWindow(s: String, t: String): String = { val need = Array.fill(128)(0); var missing = t.length; t.foreach(ch => need(ch) += 1); var left = 0; var bestStart = 0; var bestLen = s.length + 1; for (right <- 0 until s.length) { val c = s.charAt(right); if (need(c) > 0) missing -= 1; need(c) -= 1; while (missing == 0) { if (right - left + 1 < bestLen) { bestStart = left; bestLen = right - left + 1 }; val lc = s.charAt(left); need(lc) += 1; if (need(lc) > 0) missing += 1; left += 1 } }; if (bestLen > s.length) "" else s.substring(bestStart, bestStart + bestLen) }; def main(args:Array[String]):Unit={ val lines=io.Source.stdin.getLines().toArray; if(lines.nonEmpty){ val t=lines(0).toInt; print((0 until t).map(i => minWindow(lines(1+2*i), lines(2+2*i))).mkString("\n")) } } }
